args.sparql:
SELECT ?location ?locationLabel WHERE {
  wd:Q1186753 wdt:P360 ?record.
  ?record wdt:P2781 ?time.
  ?record wdt:P813 ?date.
  ?record wdt:P2873 ?location.
  SERVICE wikidata:label { bd:serviceParam wikibase:language "en". }
  FILTER(XSD:float(?time) = 50.26)
  FILTER(str(?date) = "2001-12-14")
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?cityLabel
WHERE {
  ?record wdt:P2781 ?time ;
          wdt:P585 ?date ;
          wdt:P1260 wd:Q27156 ;
          wdt:P2873 ?venue .
  ?time wikibase:quantityValue ?timeValue .
  FILTER (xsd:float(?timeValue) = 50.26)
  FILTER (?date = "2001-12-14"^^xsd:date)
  ?venue wdt:P131 ?city .
  ?city wdt:P31 wd:Q515 .
  ?city wdt:P1082 ?cityPopulation .
  ?otherCity wdt:P17 wd:Q31 ;
             wdt:P31 wd:Q515 ;
             wdt:P1082 ?otherPopulation ;
             rdfs:label ?cityLabel .
  FILTER (?otherPopulation > ?cityPopulation)
  FILTER (LANG(?cityLabel) = 'en')
}
ORDER BY DESC(?otherPopulation)
LIMIT 1
